        let isMounted = true;

        const init = async () => {
            try {
                const user = await api.getCurrentUser();
                if (!isMounted) return;
                setCurrentUser(user);

                setStatus('Requesting permissions...');
                const stream = await navigator.mediaDevices.getUserMedia({ audio: true, video: true });
                if (!isMounted) { stream.getTracks().forEach(t => t.stop()); return; }

                localStreamRef.current = stream;
                if (localVideoRef.current) localVideoRef.current.srcObject = stream;

                setStatus('Connecting to network...');

                // By connecting to the PeerJS cloud service at 0.peerjs.com, we automatically 
                // get access to their free STUN and TURN servers for NAT traversal.
                const peer = new Peer(user.id, {
                    host: '0.peerjs.com', 
                    port: 443,
                    path: '/',
                    pingInterval: 5000
                });
                peerRef.current = peer;

                const handleCallEvents = (call: any) => {
                    currentCallRef.current = call;
                    call.on('stream', (remoteStream: MediaStream) => {
                        remoteStreamRef.current = remoteStream;
                        if (remoteVideoRef.current) remoteVideoRef.current.srcObject = remoteStream;
                        setStatus('Connected');
                        setCallEstablished(true);
                    });
                    call.on('close', leaveCall);
                    call.on('error', (err: any) => {
                        console.error('Call error:', err);
                        setStatus('Call error.');
                        leaveCall();
                    });
                }

                peer.on('open', () => {
                    if (!isMounted) return;
                    setStatus('Ringing...');
                    if (friendId) {
                        const call = peer.call(friendId, stream);
                        handleCallEvents(call);
                    }
                });

                peer.on('call', (call) => {
                    if (!isMounted) return;
                    setStatus('Incoming call...');
                    call.answer(stream);
                    handleCallEvents(call);
                });

                peer.on('error', (err) => {
                    console.error('PeerJS error:', err);
                    setStatus(`Error: ${err.message}`);
                    setCallEstablished(false);
                });

                peer.on('disconnected', () => {
                    setStatus('Reconnecting network...');
                    peer.reconnect();
